package cache

type Rule struct {
	Name      string
	Category  string
	Paths     []string
	Languages []string
	System    bool
}

type ItemKind string

const (
	ItemPath   ItemKind = "path"
	ItemDocker ItemKind = "docker"
)

type Item struct {
	Name      string
	Category  string
	System    bool
	Priority  string
	Path      string
	SizeBytes int64
	SizeText  string
	FileCount int64
	Status    string
	Kind      ItemKind
}

